('clseed00001', 'admin@lizgathotel.com', 'Admin', '$2a$12$LJ3m4ys3Gz8y0Gv5Z0RBJePwOp2qO6UdXoOIlPbWv0yR1FQxSvKHy', 'superadmin', NOW(3), NOW(3));
INSERT INTO `rooms` (`id`, `slug`, `name`, `category`, `price`, `description`, `shortDescription`, `capacity`, `size`, `bedType`, `image`, `images`, `amenities`, `featured`, `isActive`, `sortOrder`, `createdAt`, `updatedAt`) VALUES
('clseed00010', 'standard-room', 'Standard Room', 'standard', 120, 'Our Standard Room offers a comfortable retreat with modern amenities, perfect for both business and leisure travelers. Enjoy a restful night''s sleep on our premium mattress, surrounded by tasteful African-inspired decor that celebrates Ghana''s rich cultural heritage.', 'A comfortable retreat with modern amenities for the discerning traveler.', 2, '28 sqm', 'Queen Bed', '/images/rooms/room-2/036.jpg', '["/images/rooms/room-2/036.jpg","/images/rooms/room-2/037.jpg","/images/rooms/room-2/038.jpg"]', '["Free Wi-Fi","Air Conditioning","Flat Screen TV","Mini Bar","Room Service","Daily Housekeeping"]', 0, 1, 0, NOW(3), NOW(3)),
('clseed00011', 'deluxe-room', 'Deluxe Room', 'deluxe', 180, 'Step into luxury with our Deluxe Room, featuring expanded living space, premium furnishings, and stunning views of Accra. The room blends contemporary comfort with authentic Ghanaian artistry, creating an unforgettable stay experience.', 'Expanded luxury with premium furnishings and city views.', 2, '38 sqm', 'King Bed', '/images/rooms/room-4/045.jpg', '["/images/rooms/room-4/045.jpg","/images/rooms/room-4/046.jpg","/images/rooms/room-4/047.jpg"]', '["Free Wi-Fi","Air Conditioning","55\\\" Smart TV","Mini Bar","Room Service","Bathrobe & Slippers","Coffee Machine","Safe Box"]', 1, 1, 1, NOW(3), NOW(3)),
('clseed00012', 'executive-suite', 'Executive Suite', 'suite', 280, 'Our Executive Suite is designed for those who demand the finest. With a separate living area, work desk, and premium bathroom amenities, this suite is perfect for extended stays or business travelers who want to unwind in style.', 'Separate living area and workspace for the executive traveler.', 3, '55 sqm', 'King Bed', '/images/rooms/room-7/055.jpg', '["/images/rooms/room-7/055.jpg","/images/rooms/room-7/056.jpg","/images/rooms/room-7/057.jpg"]', '["Free Wi-Fi","Air Conditioning","65\\\" Smart TV","Full Mini Bar","24/7 Room Service","Bathrobe & Slippers","Espresso Machine","Safe Box","Work Desk","Living Area"]', 1, 1, 2, NOW(3), NOW(3)),
('clseed00013', 'family-room', 'Family Room', 'deluxe', 220, 'Designed with families in mind, our Family Room offers generous space and thoughtful amenities for parents and children alike. Enjoy the extra room to relax while keeping the little ones entertained and comfortable.', 'Spacious comfort designed for the whole family.', 4, '48 sqm', '1 King + 2 Twin Beds', '/images/rooms/room-10/066.jpg', '["/images/rooms/room-10/066.jpg","/images/rooms/room-10/067.jpg","/images/rooms/room-10/068.jpg"]', '["Free Wi-Fi","Air Conditioning","50\\\" Smart TV","Mini Fridge","Room Service","Baby Cot Available","Game Console","Daily Housekeeping"]', 0, 1, 3, NOW(3), NOW(3)),
('clseed00014', 'presidential-suite', 'Presidential Suite', 'presidential', 450, 'The crown jewel of LIZGAT Hotel, our Presidential Suite offers unparalleled luxury across two floors. Featuring a grand living room, private dining area, and panoramic views of Accra, this suite redefines opulence. Every detail has been curated to provide an experience befitting royalty.', 'Two floors of unparalleled luxury with panoramic city views.', 4, '120 sqm', 'Super King Bed', '/images/rooms/room-11/077.jpg', '["/images/rooms/room-11/077.jpg","/images/rooms/room-11/078.jpg","/images/rooms/room-11/079.jpg"]', '["Free Wi-Fi","Climate Control","75\\\" Smart TV","Premium Mini Bar","24/7 Butler Service","Luxury Bathrobe & Slippers","Private Dining Area","Jacuzzi","Walk-in Closet","Grand Piano","Private Balcony","Espresso Machine"]', 1, 1, 4, NOW(3), NOW(3)),
('clseed00015', 'honeymoon-suite', 'Honeymoon Suite', 'suite', 350, 'Celebrate love in our exquisite Honeymoon Suite, where romance meets luxury. Rose-petal turndown service, couples'' spa treatments, and a private balcony overlooking the gardens create the perfect setting for an unforgettable romantic getaway.', 'Romance meets luxury for an unforgettable experience.', 2, '65 sqm', 'King Bed with Canopy', '/images/rooms/room-14/089.jpg', '["/images/rooms/room-14/089.jpg","/images/rooms/room-14/090.jpg","/images/rooms/room-14/091.jpg"]', '["Free Wi-Fi","Climate Control","65\\\" Smart TV","Premium Mini Bar","24/7 Room Service","Luxury Bathrobe & Slippers","Couples'' Spa Access","Jacuzzi","Rose Petal Turndown","Champagne Welcome","Private Balcony"]', 0, 1, 5, NOW(3), NOW(3));
INSERT INTO `amenities` (`id`, `amenityId`, `name`, `description`, `iconName`, `image`, `details`, `isActive`, `sortOrder`, `createdAt`, `updatedAt`) VALUES
('clseed00023', 'restaurant', 'Restaurant & Bar', 'Savor exquisite cuisine from our award-winning chefs, blending Ghanaian flavors with international fine dining.', 'UtensilsCrossed', '/images/restaurant/027.jpg', '["Breakfast buffet 6:30 - 10:30 AM","All-day dining restaurant","Rooftop bar with cocktails","Traditional Ghanaian cuisine","International menu","Private dining available"]', 1, 3, NOW(3), NOW(3)),
('clseed00024', 'conference', 'Conference Rooms', 'Host successful events in our versatile conference facilities equipped with the latest audiovisual technology.', 'Users', '/images/conference/001.jpg', '["3 fully equipped meeting rooms","Capacity up to 200 guests","Projector and screen","Video conferencing setup","Catering services available","Dedicated event coordinator"]', 1, 4, NOW(3), NOW(3)),
('clseed00025', 'business', 'Business Center', 'Stay productive with our fully equipped business center offering printing, faxing, and private workspaces.', 'Briefcase', '/images/reception/024.jpg', '["High-speed internet","Printing and scanning","Private meeting pods","Administrative assistance","Available 24/7","Complimentary coffee and tea"]', 1, 5, NOW(3), NOW(3)),
('clseed00027', 'wifi', 'Free High-Speed Wi-Fi', 'Stay connected throughout your stay with complimentary high-speed wireless internet access in all areas.', 'Wifi', '/images/reception/025.jpg', '["Complimentary for all guests","Available in all rooms and public areas","High-speed fiber connection","Streaming-ready speeds","Secure network","Technical support available"]', 1, 7, NOW(3), NOW(3)),
('clseed00028', 'concierge', 'Concierge Service', 'Our dedicated concierge team is available around the clock to assist with dining reservations, tours, and local experiences.', 'ConciergeBell', '/images/reception/023.jpg', '["24/7 availability","Restaurant reservations","Tour and activity booking","Transportation arrangements","Special occasion planning","Local area expertise"]', 1, 8, NOW(3), NOW(3)),
('clseed00029', 'laundry', 'Laundry Service', 'Keep your wardrobe fresh with our professional same-day laundry and dry-cleaning service.', 'WashingMachine', '/images/mart/017.jpg', '["Same-day service","Dry cleaning available","Express service","Ironing and pressing","Pickup from room","Eco-friendly detergents"]', 1, 9, NOW(3), NOW(3)),
('clseed00030', 'parking', 'Valet Parking', 'Enjoy hassle-free parking with our secure valet service, available for all hotel guests.', 'Car', '/images/environs/008.jpg', '["Complimentary for guests","Secure underground parking","24/7 valet service","EV charging stations","CCTV monitored","Easy access to lobby"]', 1, 10, NOW(3), NOW(3)),
('clseed00031', 'security', '24/7 Security', 'Your safety is our priority. Our professional security team ensures a safe and secure environment at all times.', 'ShieldCheck', '/images/environs/007.jpg', '["Round-the-clock security personnel","CCTV surveillance","Electronic key card access","In-room safe boxes","Fire safety systems","Emergency response team"]', 1, 11, NOW(3), NOW(3));
INSERT INTO `testimonials` (`id`, `name`, `location`, `rating`, `text`, `avatar`, `isActive`, `sortOrder`, `createdAt`, `updatedAt`) VALUES
('clseed00040', 'Kwame Asante', 'Accra, Ghana', 5, 'An absolutely exceptional experience from check-in to check-out. The staff went above and beyond to make our anniversary celebration truly special. The Presidential Suite was breathtaking!', 'KA', 1, 0, NOW(3), NOW(3)),
('clseed00041', 'Sarah Mitchell', 'London, UK', 5, 'LIZGAT Hotel exceeded all expectations. The blend of Ghanaian hospitality with world-class service is remarkable. The dining experience was divine, and the restaurant served the best jollof rice I''ve ever tasted.', 'SM', 1, 1, NOW(3), NOW(3)),
('clseed00042', 'David Osei', 'Kumasi, Ghana', 5, 'Perfect for business travel. The conference facilities are top-notch, and the Executive Suite provided a wonderful space to relax after meetings. I''ll definitely be returning on my next trip.', 'DO', 1, 2, NOW(3), NOW(3)),
('clseed00043', 'Aisha Johnson', 'New York, USA', 5, 'What a gem in Accra! The hotel grounds are stunning, the rooms are impeccably clean, and the concierge helped us plan the most amazing tour of the city. Highly recommended for any traveler!', 'AJ', 1, 3, NOW(3), NOW(3)),
('clseed00044', 'Emmanuel Mensah', 'Cape Coast, Ghana', 5, 'We hosted our wedding reception at LIZGAT Hotel and it was absolutely magical. The event team handled everything flawlessly. Our guests are still talking about how wonderful it was!', 'EM', 1, 4, NOW(3), NOW(3)),
('clseed00045', 'Chen Wei', 'Beijing, China', 5, 'Outstanding hospitality! From the moment we arrived, we felt welcomed and valued. The attention to detail in every aspect of the hotel is impressive. A true five-star experience in Ghana.', 'CW', 1, 5, NOW(3), NOW(3));
