INSERT INTO `page_content` (`id`, `page`, `section`, `content`, `sortOrder`, `createdAt`, `updatedAt`) VALUES
('clseed00100', 'about', 'story', '{"title":"Our Story","subtitle":"A Legacy of Luxury","text":"Founded in 2020, LIZGAT Hotel was born from a vision to create a world-class luxury destination in the heart of Accra. Our founders, inspired by Ghana''s rich cultural heritage and warm hospitality traditions, set out to build a hotel that would seamlessly blend African elegance with modern luxury.\\n\\nToday, LIZGAT Hotel stands as a testament to that vision. Every corner of our establishment reflects our commitment to excellence, from the carefully curated art pieces that adorn our walls to the locally sourced ingredients in our restaurant.","image":"/images/environs/005.jpg"}', 0, NOW(3), NOW(3)),
('clseed00101', 'about', 'values', '[{"icon":"Heart","title":"Warm Hospitality","description":"We treat every guest as family, ensuring a warm, personalized experience that reflects the best of Ghanaian hospitality."},{"icon":"Award","title":"Excellence","description":"We strive for perfection in every detail, from room preparation to dining service, maintaining the highest standards."},{"icon":"Globe","title":"Cultural Pride","description":"We celebrate Ghana''s rich culture and traditions, integrating local art, cuisine, and customs into the guest experience."},{"icon":"Shield","title":"Trust & Safety","description":"Your safety and privacy are paramount. We maintain rigorous security standards and respect guest confidentiality."}]', 1, NOW(3), NOW(3)),
('clseed00102', 'about', 'milestones', '[{"year":2020,"title":"Grand Opening","description":"LIZGAT Hotel opens its doors, welcoming its first guests with 80 luxury rooms."},{"year":2021,"title":"Spa & Wellness Launch","description":"Opening of our world-class spa featuring traditional Ghanaian treatments."},{"year":2022,"title":"Culinary Excellence Award","description":"Our restaurant receives the Ghana Hospitality Award for Best Hotel Dining."},{"year":2023,"title":"Expansion Complete","description":"Addition of 70 new rooms including the iconic Presidential Suite."},{"year":2024,"title":"5-Star Recognition","description":"Awarded official 5-star rating by the Ghana Tourism Authority."},{"year":2025,"title":"Sustainability Initiative","description":"Launch of our green initiative with solar power and water recycling systems."}]', 2, NOW(3), NOW(3)),
('clseed00103', 'home', 'hero', '{"title":"Experience Luxury in the Heart of Accra","subtitle":"Welcome to LIZGAT Hotel","description":"Where Ghanaian hospitality meets world-class luxury"}', 0, NOW(3), NOW(3)),
('clseed00104', 'home', 'welcome', '{"subtitle":"Welcome to LIZGAT","title":"A New Standard of Luxury in Ghana","text":"Nestled in the prestigious Airport Residential Area of Accra, LIZGAT Hotel redefines luxury hospitality in West Africa. Our commitment to excellence is reflected in every detail, from our meticulously designed rooms to our award-winning culinary experiences.","stats":[{"value":150,"suffix":"+","label":"Luxury Rooms"},{"value":50,"suffix":"K+","label":"Happy Guests"},{"value":15,"suffix":"+","label":"Awards Won"}]}', 1, NOW(3), NOW(3)),
('clseed00105', 'home', 'cta', '{"title":"Ready for an Unforgettable Experience?","description":"Book your stay at LIZGAT Hotel and discover the perfect blend of luxury, comfort, and Ghanaian hospitality."}', 2, NOW(3), NOW(3));
